import redis

# Connect to Redis server
r = redis.Redis(host='localhost', port=6379, db=0)

def execute_lua_script():
    # Get Lua script from user input
    lua_script = input("Enter the Lua script code: ")
    
    # Get number of keys and parameters
    num_keys = int(input("Enter the number of keys: "))
    num_params = int(input("Enter the number of parameters: "))
    
    # Get keys and parameters
    keys = [input(f"Enter key {i+1}: ") for i in range(num_keys)]
    params = [input(f"Enter parameter {i+1}: ") for i in range(num_params)]
    
    try:
        # Execute Lua script using redis.eval()
        result = r.eval(lua_script, num_keys, *keys, *params)
        print("Script executed successfully. Result:", result)
    except Exception as e:
        print("Error executing script:", e)

if __name__ == "__main__":
    execute_lua_script()